import React, { useState } from 'react';
import { TopNav } from '../TopNav';
import { useTheme } from '../ThemeContext';
import {
  BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid, Cell,
} from 'recharts';
import { Download } from 'lucide-react';

const payslips = [
  { month: 'June 2025',     gross: 5600, tax: 1350, net: 4250, status: 'Pending'  },
  { month: 'May 2025',      gross: 5600, tax: 1350, net: 4250, status: 'Paid'     },
  { month: 'April 2025',    gross: 5400, tax: 1290, net: 4110, status: 'Paid'     },
  { month: 'March 2025',    gross: 5400, tax: 1290, net: 4110, status: 'Paid'     },
  { month: 'February 2025', gross: 5200, tax: 1240, net: 3960, status: 'Paid'     },
  { month: 'January 2025',  gross: 5200, tax: 1240, net: 3960, status: 'Paid'     },
];

const chartData = payslips.slice().reverse().map((p) => ({
  month: p.month.split(' ')[0].slice(0, 3),
  net: p.net,
}));

const statusColors = {
  Paid:    'bg-emerald-400/10 text-emerald-400',
  Pending: 'bg-amber-400/10 text-amber-400',
};

export function SalaryPage() {
  const { theme } = useTheme();
  const textMuted = theme === 'dark' ? '#64748b' : '#94a3b8';
  const grid      = theme === 'dark' ? '#1e293b' : '#f1f5f9';
  const cardBg    = theme === 'dark' ? '#1e293b' : '#fff';
  const border    = theme === 'dark' ? '#334155' : '#e2e8f0';
  const text      = theme === 'dark' ? '#f1f5f9' : '#0f172a';

  const [selected, setSelected] = useState(null);

  return (
    <div className="flex flex-col min-h-full bg-dash-bg">
      <TopNav title="Salary" />
      <main className="p-6 space-y-6">

        {/* Summary KPIs */}
        <div className="grid grid-cols-3 gap-4">
          {[
            { label: 'Current gross',  value: '$5,600' },
            { label: 'Income tax',     value: '$1,350' },
            { label: 'Net salary',     value: '$4,250' },
          ].map((k) => (
            <div key={k.label} className="bg-dash-card border border-dash-border rounded-xl p-4 flex flex-col gap-1">
              <span className="text-dash-text-muted" style={{ fontSize: '12px' }}>{k.label}</span>
              <span className="text-dash-text" style={{ fontSize: '24px', fontWeight: 700 }}>{k.value}</span>
            </div>
          ))}
        </div>

        {/* Trend chart */}
        <div className="bg-dash-card border border-dash-border rounded-xl p-5">
          <h3 className="text-dash-text mb-4" style={{ fontSize: '14px', fontWeight: 600 }}>Net Salary Trend</h3>
          <ResponsiveContainer width="100%" height={160}>
            <BarChart data={chartData} barSize={28} margin={{ top: 0, right: 0, bottom: 0, left: -20 }}>
              <CartesianGrid strokeDasharray="3 3" stroke={grid} />
              <XAxis dataKey="month" tick={{ fontSize: 11, fill: textMuted }} axisLine={false} tickLine={false} />
              <YAxis tick={{ fontSize: 11, fill: textMuted }} axisLine={false} tickLine={false} />
              <Tooltip contentStyle={{ background: cardBg, border: `1px solid ${border}`, borderRadius: '8px', fontSize: '12px', color: text }}
                formatter={(v) => [`$${v.toLocaleString()}`, 'Net']} />
              <Bar dataKey="net" radius={[4, 4, 0, 0]}>
                {chartData.map((_, i) => (
                  <Cell key={i} fill={i === chartData.length - 1 ? '#6366f1' : (theme === 'dark' ? '#334155' : '#e2e8f0')} />
                ))}
              </Bar>
            </BarChart>
          </ResponsiveContainer>
        </div>

        {/* Payslip table */}
        <div className="bg-dash-card border border-dash-border rounded-xl overflow-hidden">
          <div className="px-5 py-4 border-b border-dash-border">
            <h3 className="text-dash-text" style={{ fontSize: '14px', fontWeight: 600 }}>Payslips</h3>
          </div>
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-dash-border">
                  {['Month', 'Gross', 'Tax', 'Net', 'Status', ''].map((h) => (
                    <th key={h} className="px-5 py-3 text-left text-dash-text-muted" style={{ fontSize: '11px', fontWeight: 600, textTransform: 'uppercase', letterSpacing: '0.05em' }}>
                      {h}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {payslips.map((row) => (
                  <tr key={row.month} className="border-b border-dash-border last:border-0 hover:bg-dash-sidebar-hover transition-colors">
                    <td className="px-5 py-3 text-dash-text" style={{ fontSize: '13px' }}>{row.month}</td>
                    <td className="px-5 py-3 text-dash-text-secondary" style={{ fontSize: '13px' }}>${row.gross.toLocaleString()}</td>
                    <td className="px-5 py-3 text-red-400" style={{ fontSize: '13px' }}>-${row.tax.toLocaleString()}</td>
                    <td className="px-5 py-3 text-dash-primary" style={{ fontSize: '13px', fontWeight: 600 }}>${row.net.toLocaleString()}</td>
                    <td className="px-5 py-3">
                      <span className={`px-2 py-0.5 rounded-full text-xs font-medium ${statusColors[row.status]}`}>{row.status}</span>
                    </td>
                    <td className="px-5 py-3">
                      <button className="flex items-center gap-1 text-dash-text-muted hover:text-dash-primary transition-colors" style={{ fontSize: '12px' }}>
                        <Download size={13} />
                        PDF
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

      </main>
    </div>
  );
}
